      "content": "const express = require('express');
const service = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', (req, res) => {
  const { projectId } = req.params;
  const status = req.query.status;
  const tasks = service.getTasksByProjectId(projectId);
  if (!tasks) {
    return sendError(res, 404, 'NOT_FOUND', 'Project not found.');
  }
  const filteredTasks = status ? tasks.filter(task => task.status === status) : tasks;
  res.json({ tasks: filteredTasks });
});

router.post('/', (req, res) => {
  const { projectId } = req.params;
  const task = service.createTask(projectId);
  if (!task) {
    return sendError(res, 500, 'INTERNAL_ERROR', 'Failed to create task.');
  }
  res.status(201).json({ task });
});

router.patch('/:taskId', (req, res) => {
  const { projectId, taskId } = req.params;
  const { status } = req.body;
  if (!status || !['todo', 'done'].includes(status)) {
    return sendError(res, 400, 'INVALID_INPUT', 'Status must be either todo or done.');
  }
  const task = service.updateTask(projectId, taskId, status);
  if (!task) {
    return sendError(res, 500, 'INTERNAL_ERROR', 'Failed to update task.');
  }
  res.json({ task });
});

module.exports = router;
