  const project = getProjectById(projectId);
  if (!project) {
    return null;
  }
  const task = project.tasks.find(task => task.id === taskId);
  if (!task || !task.comments) {
    return [];
  }
  return task.comments;
}

module.exports = {
  addComment,
  getCommentsByTaskId,
};
